import { Subject, Question } from '@/types'

export const SEED_QUESTIONS: Omit<Question, 'id'>[] = [

  // ── MATH Grade 3 ──────────────────────────────────────────────
  { subject: 'math', grade_level: 3, question_text: 'What is 7 × 8?', type: 'typed', options: null, correct_answer: '56', explanation: 'Multiply 7 by 8. Think of it as 7 groups of 8: 8+8+8+8+8+8+8 = 56. Or remember: 7×8 = 56 (seven ate fifty-six! 🍽️).', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 9 × 6?', type: 'typed', options: null, correct_answer: '54', explanation: 'Multiply 9 by 6. A trick: 9 × 6 = (10 × 6) − 6 = 60 − 6 = 54. The tens digit is always one less than the number you multiply by 9.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 144 ÷ 12?', type: 'typed', options: null, correct_answer: '12', explanation: 'Ask: "12 times what equals 144?" 12 × 10 = 120, and 12 × 2 = 24, so 12 × 12 = 144. Therefore 144 ÷ 12 = 12.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 8 × 8?', type: 'typed', options: null, correct_answer: '64', explanation: 'Multiply 8 by itself. 8 × 8 is a square number. Think: 8 × 8 = (8 × 4) × 2 = 32 × 2 = 64.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 63 ÷ 7?', type: 'typed', options: null, correct_answer: '9', explanation: 'Ask: "7 times what equals 63?" Count up: 7×7=49, 7×8=56, 7×9=63. So 63 ÷ 7 = 9.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'Which fraction is larger: 1/2 or 1/3?', type: 'multiple_choice', options: ['1/2', '1/3', 'They are equal', 'Cannot compare'], correct_answer: '1/2', explanation: 'When the top number (numerator) is the same, the bigger the bottom number (denominator), the smaller the piece. Cutting a pie into 2 pieces gives bigger slices than cutting into 3 pieces. So 1/2 > 1/3.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is the perimeter of a square with side 5 cm?', type: 'multiple_choice', options: ['10 cm', '15 cm', '20 cm', '25 cm'], correct_answer: '20 cm', explanation: 'Perimeter means add up all sides. A square has 4 equal sides, so perimeter = 4 × side = 4 × 5 = 20 cm.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 4 × 7?', type: 'typed', options: null, correct_answer: '28', explanation: 'Multiply 4 by 7. Think: 4 × 7 = (4 × 5) + (4 × 2) = 20 + 8 = 28. Or count by 7s: 7, 14, 21, 28.', difficulty: 1, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 36 ÷ 6?', type: 'typed', options: null, correct_answer: '6', explanation: 'Ask: "6 times what equals 36?" Count by 6s: 6, 12, 18, 24, 30, 36 — that\'s 6 steps. So 36 ÷ 6 = 6.', difficulty: 1, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'How many sides does a pentagon have?', type: 'multiple_choice', options: ['4', '5', '6', '8'], correct_answer: '5', explanation: '"Penta" means 5 in Greek (like pentathlon = 5 sports). A pentagon has 5 sides. Helpful: tri=3, quad=4, penta=5, hex=6, oct=8.', difficulty: 1, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'Round 47 to the nearest ten.', type: 'multiple_choice', options: ['40', '45', '50', '47'], correct_answer: '50', explanation: 'Look at the ones digit: 7. The rule is — if it\'s 5 or more, round up; if it\'s 4 or less, round down. Since 7 ≥ 5, round 47 up to 50.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 3 × 9?', type: 'typed', options: null, correct_answer: '27', explanation: '3 × 9 = 3 × (10 − 1) = 30 − 3 = 27. Or use the 9s trick: the digits always add up to 9. 2+7 = 9 ✓', difficulty: 1, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 48 ÷ 8?', type: 'typed', options: null, correct_answer: '6', explanation: 'Count by 8s until you reach 48: 8, 16, 24, 32, 40, 48 — that\'s 6 steps. So 48 ÷ 8 = 6.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 125 + 75?', type: 'typed', options: null, correct_answer: '200', explanation: 'Add the tens and ones: 125 + 75. Notice 25 + 75 = 100, then 100 + 100 = 200. Break it into friendly numbers!', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'Which shape has 0 corners?', type: 'multiple_choice', options: ['Square', 'Triangle', 'Circle', 'Rectangle'], correct_answer: 'Circle', explanation: 'Corners (vertices) are sharp points where sides meet. A circle has no straight sides and no points — it\'s a perfectly round curve, so it has 0 corners.', difficulty: 1, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 200 - 85?', type: 'typed', options: null, correct_answer: '115', explanation: 'Subtract in steps: 200 − 85. First do 200 − 80 = 120, then 120 − 5 = 115.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 6 × 6?', type: 'typed', options: null, correct_answer: '36', explanation: '6 × 6 is a square number. Think: 6 × 6 = (6 × 5) + 6 = 30 + 6 = 36. Memorise it: "6 squared = 36".', difficulty: 1, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What fraction of a pizza is 2 out of 4 slices?', type: 'multiple_choice', options: ['1/4', '1/2', '3/4', '2/3'], correct_answer: '1/2', explanation: 'Write it as 2/4. Then simplify: divide top and bottom by 2 → 1/2. You can also see it visually: 2 of 4 equal slices is exactly half the pizza.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'What is 7 × 3?', type: 'typed', options: null, correct_answer: '21', explanation: 'Count by 7s: 7, 14, 21 — three steps. Or count by 3s: 3, 6, 9, 12, 15, 18, 21 — seven steps. Both reach 21.', difficulty: 1, source: 'curated' },
  { subject: 'math', grade_level: 3, question_text: 'How many minutes in an hour?', type: 'typed', options: null, correct_answer: '60', explanation: 'This is a fact to memorise: 1 hour = 60 minutes. A clock face has 60 minute marks around it. Each number represents 5 minutes (12 numbers × 5 = 60).', difficulty: 1, source: 'curated' },

  // ── MATH Grade 5 ──────────────────────────────────────────────
  { subject: 'math', grade_level: 5, question_text: 'What is 25% of 80?', type: 'typed', options: null, correct_answer: '20', explanation: '25% means 25 out of 100, which equals 1/4. So find 1/4 of 80: 80 ÷ 4 = 20. Quick trick: 25% = divide by 4.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is the area of a rectangle 6m × 9m?', type: 'typed', options: null, correct_answer: '54', explanation: 'Area of a rectangle = length × width = 6 × 9 = 54 square metres. Always multiply both dimensions to get area.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 3/4 + 1/2?', type: 'multiple_choice', options: ['4/6', '5/4', '1 1/4', '1/2'], correct_answer: '5/4', explanation: 'Make the denominators match. 1/2 = 2/4. Now add: 3/4 + 2/4 = 5/4. Since 5/4 > 1, it\'s an improper fraction (also written 1¼).', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'Which number is prime?', type: 'multiple_choice', options: ['9', '15', '17', '21'], correct_answer: '17', explanation: 'A prime number has exactly 2 factors: 1 and itself. 9 = 3×3, 15 = 3×5, 21 = 3×7 (not prime). 17 can only be divided evenly by 1 and 17 — so it\'s prime.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 50% of 120?', type: 'typed', options: null, correct_answer: '60', explanation: '50% means half. So find half of 120: 120 ÷ 2 = 60. Quick trick: 50% = divide by 2.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 2/3 of 90?', type: 'typed', options: null, correct_answer: '60', explanation: 'First find 1/3 of 90: 90 ÷ 3 = 30. Then multiply by 2 (for 2/3): 30 × 2 = 60. Rule: to find a fraction of a number, divide by the bottom, multiply by the top.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is the LCM of 4 and 6?', type: 'multiple_choice', options: ['8', '10', '12', '24'], correct_answer: '12', explanation: 'LCM = Least Common Multiple. List multiples: 4→4,8,12,16... and 6→6,12,18... The smallest number on both lists is 12. So LCM(4,6) = 12.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 1.5 × 4?', type: 'typed', options: null, correct_answer: '6', explanation: 'Break it up: 1.5 × 4 = (1 × 4) + (0.5 × 4) = 4 + 2 = 6. Or think: 1.5 is the same as 3/2, so 3/2 × 4 = 12/2 = 6.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 7/8 - 1/4?', type: 'multiple_choice', options: ['5/8', '6/8', '3/4', '1/2'], correct_answer: '5/8', explanation: 'Convert 1/4 to eighths: 1/4 = 2/8. Now subtract: 7/8 − 2/8 = 5/8. Always make denominators equal before adding or subtracting fractions.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'Which is greatest: 0.9, 0.09, 0.99?', type: 'multiple_choice', options: ['0.9', '0.09', '0.99', 'All equal'], correct_answer: '0.99', explanation: 'Compare digit by digit from left: all start with 0. Next: 0.9 has 9 tenths, 0.99 has 9 tenths AND 9 hundredths. So 0.99 > 0.9 > 0.09. 0.99 is greatest.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 10% of 250?', type: 'typed', options: null, correct_answer: '25', explanation: '10% means 10 out of 100, or 1/10. To find 10% of any number, just move the decimal point one place left: 250 → 25.0 = 25.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is the GCF of 12 and 18?', type: 'multiple_choice', options: ['3', '6', '9', '12'], correct_answer: '6', explanation: 'GCF = Greatest Common Factor. Factors of 12: 1,2,3,4,6,12. Factors of 18: 1,2,3,6,9,18. The biggest number on both lists is 6. So GCF(12,18) = 6.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 0.75 as a fraction?', type: 'multiple_choice', options: ['1/4', '1/2', '3/4', '7/5'], correct_answer: '3/4', explanation: '0.75 means 75 hundredths = 75/100. Simplify by dividing top and bottom by 25: 75÷25 = 3, 100÷25 = 4. So 0.75 = 3/4.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is the volume of a box 3×4×5?', type: 'typed', options: null, correct_answer: '60', explanation: 'Volume = length × width × height = 3 × 4 × 5. First: 3 × 4 = 12. Then: 12 × 5 = 60 cubic units.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 15% of 200?', type: 'typed', options: null, correct_answer: '30', explanation: 'Find 10% first: 200 × 10% = 20. Then find 5%: half of 10% = 10. Add them: 10% + 5% = 15%, so 20 + 10 = 30.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'How many faces does a cube have?', type: 'typed', options: null, correct_answer: '6', explanation: 'A cube looks like a dice or box. It has: top, bottom, front, back, left side, right side = 6 faces. All faces are equal squares.', difficulty: 2, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 4² + 3²?', type: 'typed', options: null, correct_answer: '25', explanation: '4² = 4 × 4 = 16. 3² = 3 × 3 = 9. Add them: 16 + 9 = 25. This is actually related to the Pythagorean theorem (3-4-5 triangle)!', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'Convert 3/5 to a decimal.', type: 'multiple_choice', options: ['0.35', '0.6', '0.53', '0.65'], correct_answer: '0.6', explanation: 'Divide the top by the bottom: 3 ÷ 5 = 0.6. Alternatively, convert to tenths: 3/5 = 6/10 = 0.6. Think: 5 goes into 3.0 once every 0.6.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is 1000 ÷ 25?', type: 'typed', options: null, correct_answer: '40', explanation: 'Think: how many 25s make 1000? 25 × 4 = 100, so 25 × 40 = 1000. Or: 1000 ÷ 25 = 1000 ÷ 25 = 40 × (100÷100) = 40.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 5, question_text: 'What is the perimeter of a triangle with sides 5, 7, and 9?', type: 'typed', options: null, correct_answer: '21', explanation: 'Perimeter = add all sides together. 5 + 7 + 9 = 21 units. Perimeter always means "total distance around the outside."', difficulty: 2, source: 'curated' },

  // ── MATH Grade 8 ──────────────────────────────────────────────
  { subject: 'math', grade_level: 8, question_text: 'Solve for x: 2x + 6 = 18', type: 'typed', options: null, correct_answer: '6', explanation: 'Isolate x step by step. Step 1: subtract 6 from both sides → 2x = 12. Step 2: divide both sides by 2 → x = 6. Always do the same operation to both sides.', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the square root of 169?', type: 'typed', options: null, correct_answer: '13', explanation: 'Ask: what number × itself = 169? Try 13: 13 × 13 = 169. ✓ Memorise perfect squares: 1,4,9,16,25,36,49,64,81,100,121,144,169.', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the slope of y = 3x - 7?', type: 'multiple_choice', options: ['-7', '3', '7', '-3'], correct_answer: '3', explanation: 'In slope-intercept form y = mx + b, "m" is the slope and "b" is the y-intercept. Here y = 3x − 7, so m = 3 (slope) and b = −7 (y-intercept).', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is 2³ × 2²?', type: 'multiple_choice', options: ['2⁵', '2⁶', '4⁵', '8'], correct_answer: '2⁵', explanation: 'When multiplying same bases, ADD the exponents: 2³ × 2² = 2^(3+2) = 2⁵. This is the Product Rule of Exponents. (2⁵ = 32)', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'Solve: 3x - 5 = 16', type: 'typed', options: null, correct_answer: '7', explanation: 'Step 1: add 5 to both sides → 3x = 21. Step 2: divide both sides by 3 → x = 7. Check: 3(7) − 5 = 21 − 5 = 16 ✓', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the y-intercept of y = 2x + 5?', type: 'typed', options: null, correct_answer: '5', explanation: 'In y = mx + b form, "b" is the y-intercept (where the line crosses the y-axis, when x = 0). Here b = 5. Plug in x=0: y = 2(0) + 5 = 5. ✓', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is √64?', type: 'typed', options: null, correct_answer: '8', explanation: 'Ask: what number × itself = 64? 8 × 8 = 64. So √64 = 8. Remember: 8 is the square root of 64 because 8² = 64.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the area of a circle with radius 7? (use π≈3.14)', type: 'multiple_choice', options: ['43.96', '153.86', '21.98', '49'], correct_answer: '153.86', explanation: 'Area of a circle = π × r². r = 7, so r² = 49. Then 3.14 × 49 = 153.86. Remember the formula: A = πr² (not πd, that\'s circumference!).', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'Simplify: 4x + 3x - 2x', type: 'typed', options: null, correct_answer: '5x', explanation: 'Combine like terms — terms with the same variable. Think of x as a unit: 4x + 3x = 7x, then 7x − 2x = 5x. Same as 4 apples + 3 apples − 2 apples = 5 apples.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is (-3)²?', type: 'typed', options: null, correct_answer: '9', explanation: '(-3)² = (-3) × (-3). Negative × Negative = Positive. So (−3) × (−3) = +9. Important: (−3)² = 9, but −3² = −9 (different!).', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'If y = 2x and x = 5, what is y?', type: 'typed', options: null, correct_answer: '10', explanation: 'Substitute x = 5 into the equation: y = 2x = 2 × 5 = 10. Substitution means replacing the variable with the given value.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is 5² - 4²?', type: 'typed', options: null, correct_answer: '9', explanation: 'Calculate each square first. 5² = 25, 4² = 16. Then subtract: 25 − 16 = 9. (Fun fact: this also equals (5+4)(5−4) = 9×1 = 9 — the difference of squares formula!)' , difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the Pythagorean theorem?', type: 'multiple_choice', options: ['a+b=c', 'a²+b²=c²', 'a×b=c²', '2a+b=c'], correct_answer: 'a²+b²=c²', explanation: 'In a right triangle, the two shorter sides (legs) are a and b, and the longest side (hypotenuse) is c. The theorem says: a² + b² = c². Example: 3² + 4² = 9 + 16 = 25 = 5².', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'Solve: x/4 = 8', type: 'typed', options: null, correct_answer: '32', explanation: 'To undo division, multiply both sides by 4: x/4 × 4 = 8 × 4 → x = 32. Check: 32/4 = 8 ✓', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is 3⁴?', type: 'typed', options: null, correct_answer: '81', explanation: '3⁴ means 3 multiplied by itself 4 times: 3 × 3 × 3 × 3. Step by step: 3×3=9, 9×3=27, 27×3=81.', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the mean of 4, 8, 12, 16?', type: 'typed', options: null, correct_answer: '10', explanation: 'Mean = sum ÷ count. Add all numbers: 4+8+12+16 = 40. Count: 4 numbers. Mean = 40 ÷ 4 = 10.', difficulty: 3, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'In a right triangle, legs are 3 and 4. What is the hypotenuse?', type: 'typed', options: null, correct_answer: '5', explanation: 'Use the Pythagorean theorem: a² + b² = c². So 3² + 4² = c² → 9 + 16 = 25 → c = √25 = 5. The 3-4-5 triangle is the most famous right triangle!', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the slope between (0,0) and (4,8)?', type: 'typed', options: null, correct_answer: '2', explanation: 'Slope = rise ÷ run = (change in y) ÷ (change in x). Rise = 8−0 = 8. Run = 4−0 = 4. Slope = 8/4 = 2.', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'Solve: 2(x + 3) = 14', type: 'typed', options: null, correct_answer: '4', explanation: 'Step 1: Distribute — 2×x + 2×3 = 14 → 2x + 6 = 14. Step 2: subtract 6 from both sides → 2x = 8. Step 3: divide by 2 → x = 4. Check: 2(4+3) = 2×7 = 14 ✓', difficulty: 4, source: 'curated' },
  { subject: 'math', grade_level: 8, question_text: 'What is the median of 3, 7, 9, 11, 15?', type: 'typed', options: null, correct_answer: '9', explanation: 'Median = middle value when numbers are sorted. The list is already sorted: 3, 7, [9], 11, 15. There are 5 numbers, so the middle (3rd) number is 9.', difficulty: 3, source: 'curated' },

  // ── SCIENCE Grade 4 ──────────────────────────────────────────
  { subject: 'science', grade_level: 4, question_text: 'What planet is closest to the Sun?', type: 'multiple_choice', options: ['Venus', 'Earth', 'Mercury', 'Mars'], correct_answer: 'Mercury', explanation: 'The order of planets from the Sun is: Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune. Mercury is first — and closest. Memory trick: "My Very Energetic Mother Just Served Us Nachos."', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What gas do plants absorb during photosynthesis?', type: 'multiple_choice', options: ['Oxygen', 'Nitrogen', 'Carbon Dioxide', 'Hydrogen'], correct_answer: 'Carbon Dioxide', explanation: 'Plants take in CO₂ (carbon dioxide) through tiny pores called stomata in their leaves. They use sunlight + CO₂ + water to make glucose (food) and release oxygen. That\'s why plants clean our air!', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'How many bones are in the adult human body?', type: 'multiple_choice', options: ['196', '206', '216', '226'], correct_answer: '206', explanation: 'Adults have 206 bones. Babies are born with about 270–300 bones, but many fuse together as we grow. The femur (thigh bone) is the longest; the stirrup in your ear is the smallest.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What is the center of an atom called?', type: 'multiple_choice', options: ['Electron', 'Proton', 'Nucleus', 'Neutron'], correct_answer: 'Nucleus', explanation: 'An atom has a nucleus at the center (containing protons and neutrons) with electrons orbiting around it. "Nucleus" is Latin for kernel or core — it\'s the heart of the atom.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What do plants need to make food?', type: 'multiple_choice', options: ['Moonlight and water', 'Sunlight, water and CO2', 'Oxygen and soil', 'Rain and wind'], correct_answer: 'Sunlight, water and CO2', explanation: 'Photosynthesis equation: sunlight + water + CO₂ → glucose + oxygen. Plants use chlorophyll in their leaves to capture sunlight as energy to turn CO₂ and water into sugar (food).', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What is the largest planet in our solar system?', type: 'multiple_choice', options: ['Saturn', 'Neptune', 'Jupiter', 'Uranus'], correct_answer: 'Jupiter', explanation: 'Jupiter is so large that all other planets in our solar system could fit inside it! It\'s a gas giant, mostly made of hydrogen and helium, with the famous Great Red Spot storm.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What state of matter has no definite shape or volume?', type: 'multiple_choice', options: ['Solid', 'Liquid', 'Gas', 'Plasma'], correct_answer: 'Gas', explanation: 'Solids: fixed shape AND volume. Liquids: fixed volume, no fixed shape. Gases: NO fixed shape, NO fixed volume — they expand to fill their container. Air in a balloon is a gas.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'Which animal is a mammal?', type: 'multiple_choice', options: ['Salmon', 'Eagle', 'Dolphin', 'Frog'], correct_answer: 'Dolphin', explanation: 'Mammals are warm-blooded, breathe air, have hair/fur, and feed young with milk. Dolphins breathe air through blowholes and nurse their calves with milk — even though they live in water!', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What do we call animals that eat only plants?', type: 'multiple_choice', options: ['Carnivore', 'Omnivore', 'Herbivore', 'Predator'], correct_answer: 'Herbivore', explanation: '"Herbi" comes from Latin for plant (herb). "Vore" means eater. So Herbivore = plant eater. Carnivore = meat eater (carni = meat). Omnivore = both (omni = all).', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What is the process of water turning into vapor called?', type: 'multiple_choice', options: ['Condensation', 'Evaporation', 'Precipitation', 'Sublimation'], correct_answer: 'Evaporation', explanation: 'Evaporation: liquid water → water vapor (heats up and escapes into air). Condensation is the opposite (vapor → liquid, like dew on glass). Precipitation is rain/snow falling.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'How many planets are in our solar system?', type: 'typed', options: null, correct_answer: '8', explanation: 'The 8 planets: Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune. Pluto was reclassified as a "dwarf planet" in 2006, leaving us with 8 official planets.', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What organ pumps blood through the body?', type: 'multiple_choice', options: ['Lungs', 'Brain', 'Heart', 'Liver'], correct_answer: 'Heart', explanation: 'The heart is a muscle that beats 60–100 times per minute, pumping blood through blood vessels. Blood carries oxygen and nutrients to every cell in your body and brings back carbon dioxide.', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What is the hardest natural substance on Earth?', type: 'multiple_choice', options: ['Gold', 'Iron', 'Diamond', 'Quartz'], correct_answer: 'Diamond', explanation: 'Diamonds score 10 on the Mohs hardness scale (the highest possible). They\'re made of pure carbon atoms arranged in a crystal structure so tight that almost nothing can scratch them.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What gas do humans breathe out?', type: 'multiple_choice', options: ['Oxygen', 'Nitrogen', 'Carbon Dioxide', 'Hydrogen'], correct_answer: 'Carbon Dioxide', explanation: 'We breathe IN oxygen (O₂) which cells use for energy. A waste product is carbon dioxide (CO₂) which we breathe OUT. Plants then use that CO₂ in photosynthesis — a perfect cycle!', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'Which part of the plant absorbs water from the soil?', type: 'multiple_choice', options: ['Leaves', 'Stem', 'Roots', 'Flowers'], correct_answer: 'Roots', explanation: 'Roots anchor the plant and absorb water and minerals from the soil using tiny root hairs. The stem then carries water upward to the leaves and flowers.', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What type of rock is formed from cooled lava?', type: 'multiple_choice', options: ['Sedimentary', 'Metamorphic', 'Igneous', 'Limestone'], correct_answer: 'Igneous', explanation: '"Igneous" comes from the Latin word "ignis" meaning fire. Igneous rocks form when magma (underground) or lava (above ground) cools and hardens. Granite and basalt are examples.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What is the closest star to Earth?', type: 'multiple_choice', options: ['Sirius', 'Alpha Centauri', 'The Sun', 'Polaris'], correct_answer: 'The Sun', explanation: 'The Sun is a star — our star! It\'s about 150 million km away. The next closest star (Proxima Centauri) is 4.2 light-years away, which is about 40 trillion km. The Sun is incredibly close by comparison.', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What layer of the Earth do we live on?', type: 'multiple_choice', options: ['Mantle', 'Core', 'Crust', 'Magma'], correct_answer: 'Crust', explanation: 'Earth has 4 layers: crust (outer), mantle, outer core, inner core. The crust is the thin, solid outer shell we live on — like the skin of an apple. It\'s only about 30 km thick under land.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'What force pulls objects toward Earth?', type: 'multiple_choice', options: ['Magnetism', 'Gravity', 'Friction', 'Tension'], correct_answer: 'Gravity', explanation: 'Gravity is a force that attracts objects with mass toward each other. Earth\'s gravity pulls everything toward its center, which is why things fall down and why you have weight.', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 4, question_text: 'Which planet has rings around it?', type: 'multiple_choice', options: ['Mars', 'Venus', 'Saturn', 'Mercury'], correct_answer: 'Saturn', explanation: 'Saturn is famous for its spectacular ring system made of ice and rock particles. Saturn is the second-largest planet and has over 80 moons. (Fun fact: all gas giants have rings, but Saturn\'s are the most visible.)', difficulty: 2, source: 'curated' },

  // ── SCIENCE Grade 7 ──────────────────────────────────────────
  { subject: 'science', grade_level: 7, question_text: 'What is the chemical symbol for water?', type: 'typed', options: null, correct_answer: 'H2O', explanation: 'Water is made of 2 Hydrogen atoms and 1 Oxygen atom bonded together. H = Hydrogen, O = Oxygen, and the "2" means 2 hydrogen atoms. So H₂O = 2H + O.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What organelle is the powerhouse of the cell?', type: 'multiple_choice', options: ['Nucleus', 'Ribosome', 'Mitochondria', 'Vacuole'], correct_answer: 'Mitochondria', explanation: 'Mitochondria produce ATP (energy) through cellular respiration — they break down glucose using oxygen to release energy the cell can use. Every time you move, mitochondria are working!', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What force keeps planets in orbit?', type: 'multiple_choice', options: ['Magnetism', 'Friction', 'Gravity', 'Nuclear force'], correct_answer: 'Gravity', explanation: 'The Sun\'s gravity pulls planets toward it, while planets move fast enough sideways to keep "falling" around the Sun in an orbit. Without gravity, planets would fly off in straight lines into space.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is the speed of light?', type: 'multiple_choice', options: ['300,000 km/s', '150,000 km/s', '3,000 km/s', '30,000 km/s'], correct_answer: '300,000 km/s', explanation: 'Light travels at about 300,000 km/s (or 3×10⁸ m/s). This is the fastest speed in the universe. Light from the Sun takes 8 minutes to reach Earth, even at that speed!', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is the chemical symbol for oxygen?', type: 'typed', options: null, correct_answer: 'O', explanation: 'The chemical symbol for oxygen is simply O, from its name. It\'s element number 8 on the periodic table. Oxygen gas in the air is O₂ (two oxygen atoms bonded), but the element symbol is just O.', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is DNA?', type: 'multiple_choice', options: ['A type of protein', 'Genetic material', 'A cell membrane', 'An enzyme'], correct_answer: 'Genetic material', explanation: 'DNA (Deoxyribonucleic Acid) carries genetic instructions for all living things. It\'s like a blueprint or instruction manual that tells cells how to build proteins and determines traits like eye color.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'How many chromosomes do humans have?', type: 'multiple_choice', options: ['23', '46', '48', '22'], correct_answer: '46', explanation: 'Humans have 46 chromosomes arranged in 23 pairs. One chromosome in each pair comes from your mother and one from your father. Chromosomes are made of DNA and contain your genes.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is Newton\'s first law about?', type: 'multiple_choice', options: ['Gravity', 'Inertia', 'Acceleration', 'Friction'], correct_answer: 'Inertia', explanation: 'Newton\'s 1st Law (Law of Inertia): an object at rest stays at rest, and an object in motion stays in motion unless acted on by an outside force. This is why you jerk forward when a car brakes suddenly.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What part of the cell controls its activities?', type: 'multiple_choice', options: ['Cell wall', 'Nucleus', 'Ribosome', 'Cytoplasm'], correct_answer: 'Nucleus', explanation: 'The nucleus is the "control center" of the cell. It contains DNA with instructions for making proteins and regulating cell activities. It\'s surrounded by a nuclear membrane to protect the DNA.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is the process plants use to make food?', type: 'multiple_choice', options: ['Respiration', 'Digestion', 'Photosynthesis', 'Fermentation'], correct_answer: 'Photosynthesis', explanation: 'Photosynthesis: sunlight + CO₂ + water → glucose + oxygen. "Photo" means light, "synthesis" means making. Chlorophyll (green pigment) captures light energy to power this reaction.', difficulty: 1, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is H₂SO₄?', type: 'multiple_choice', options: ['Water', 'Sulfuric acid', 'Hydrochloric acid', 'Salt water'], correct_answer: 'Sulfuric acid', explanation: 'H₂SO₄ = 2 Hydrogen + 1 Sulfur + 4 Oxygen atoms. This is sulfuric acid, one of the strongest and most widely used acids. HCl is hydrochloric acid, and H₂O is water.', difficulty: 4, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What type of energy does a moving object have?', type: 'multiple_choice', options: ['Potential', 'Chemical', 'Kinetic', 'Nuclear'], correct_answer: 'Kinetic', explanation: '"Kinetic" comes from the Greek word for motion. Kinetic energy = energy of movement. Formula: KE = ½mv². Potential energy is stored energy (like a ball held up high before dropping).', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is the atomic number of carbon?', type: 'typed', options: null, correct_answer: '6', explanation: 'The atomic number = number of protons in the nucleus. Carbon has 6 protons. On the periodic table, it\'s element 6, symbol C, in period 2. Carbon is the basis of all life on Earth.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What organ removes waste from blood?', type: 'multiple_choice', options: ['Liver', 'Heart', 'Kidneys', 'Lungs'], correct_answer: 'Kidneys', explanation: 'Kidneys filter about 200 litres of blood daily, removing waste products (like urea) and excess water, creating urine. The liver also cleans blood, but kidneys specifically filter waste into urine.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is the outermost layer of the Earth?', type: 'multiple_choice', options: ['Mantle', 'Crust', 'Inner core', 'Outer core'], correct_answer: 'Crust', explanation: 'Earth\'s layers from outside in: crust → mantle → outer core → inner core. The crust is the thin solid outermost layer. Oceanic crust (~7km thick) is thinner than continental crust (~35km).', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What do we call organisms that make their own food?', type: 'multiple_choice', options: ['Consumers', 'Decomposers', 'Producers', 'Predators'], correct_answer: 'Producers', explanation: 'Producers make their own food via photosynthesis — plants, algae, and some bacteria. Consumers eat other organisms. Decomposers break down dead matter. Producers are the base of every food chain.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is the unit of electric current?', type: 'multiple_choice', options: ['Volt', 'Watt', 'Ampere', 'Ohm'], correct_answer: 'Ampere', explanation: 'Ampere (A) measures electric current (flow of charge). Volt (V) measures voltage (electric potential). Ohm (Ω) measures resistance. Watt (W) measures power. Think: Amps = how much water flows, Volts = water pressure.', difficulty: 3, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What gas makes up most of Earth\'s atmosphere?', type: 'multiple_choice', options: ['Oxygen', 'Carbon dioxide', 'Nitrogen', 'Argon'], correct_answer: 'Nitrogen', explanation: 'Earth\'s atmosphere is about 78% Nitrogen, 21% Oxygen, and 1% other gases (mainly Argon and CO₂). We need oxygen to breathe, but nitrogen is the most abundant. It\'s essential for proteins and DNA.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What is the formula for speed?', type: 'multiple_choice', options: ['Speed = mass × time', 'Speed = distance ÷ time', 'Speed = force × time', 'Speed = distance × time'], correct_answer: 'Speed = distance ÷ time', explanation: 'Speed = Distance ÷ Time. If you travel 60 km in 2 hours, speed = 60÷2 = 30 km/h. Memory trick: "DST triangle" — D on top, S×T on bottom. Cover what you want: D=S×T, S=D/T, T=D/S.', difficulty: 2, source: 'curated' },
  { subject: 'science', grade_level: 7, question_text: 'What are the building blocks of proteins?', type: 'multiple_choice', options: ['Fatty acids', 'Amino acids', 'Glucose', 'Nucleotides'], correct_answer: 'Amino acids', explanation: 'Proteins are chains of amino acids. There are 20 amino acids, and different sequences make different proteins (like hemoglobin, enzymes, muscles). Nucleotides build DNA, glucose is a sugar, fatty acids build fats.', difficulty: 4, source: 'curated' },

  // ── HISTORY Grade 5 ──────────────────────────────────────────
  { subject: 'history', grade_level: 5, question_text: 'In what year did the US declare independence?', type: 'typed', options: null, correct_answer: '1776', explanation: 'The Declaration of Independence was signed on July 4, 1776, by the Second Continental Congress. That\'s why July 4th is celebrated as Independence Day in the USA each year.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'Who was the first President of the United States?', type: 'multiple_choice', options: ['John Adams', 'Thomas Jefferson', 'George Washington', 'Benjamin Franklin'], correct_answer: 'George Washington', explanation: 'George Washington was elected the first US President in 1789 and served two terms. He led the Continental Army during the Revolutionary War and is known as the "Father of His Country."', difficulty: 1, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What ocean did Columbus cross to reach the Americas?', type: 'multiple_choice', options: ['Pacific', 'Atlantic', 'Indian', 'Arctic'], correct_answer: 'Atlantic', explanation: 'In 1492, Columbus sailed west from Spain across the Atlantic Ocean and reached the Caribbean islands. He thought he\'d reached Asia (the "Indies"), which is why he called the natives "Indians."', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'Which ancient wonder was in Egypt?', type: 'multiple_choice', options: ['Colosseum', 'Great Pyramid of Giza', 'Parthenon', 'Stonehenge'], correct_answer: 'Great Pyramid of Giza', explanation: 'The Great Pyramid of Giza, built around 2560 BC, is the only one of the original Seven Wonders of the Ancient World still standing. It was built as a tomb for Pharaoh Khufu.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What ship did the Pilgrims sail to America?', type: 'multiple_choice', options: ['Santa Maria', 'Mayflower', 'Titanic', 'Pinta'], correct_answer: 'Mayflower', explanation: 'The Pilgrims sailed on the Mayflower in 1620 from England to Plymouth, Massachusetts. The Santa Maria and Pinta were Columbus\'s ships (1492). The Titanic was a luxury liner that sank in 1912.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'Which country gifted the Statue of Liberty to the US?', type: 'multiple_choice', options: ['England', 'Spain', 'France', 'Italy'], correct_answer: 'France', explanation: 'France gifted the Statue of Liberty to the United States in 1886 as a symbol of freedom and friendship. French sculptor Frédéric Auguste Bartholdi designed it, and Alexandre Gustave Eiffel built the inner framework.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'Who wrote the Declaration of Independence?', type: 'multiple_choice', options: ['George Washington', 'Benjamin Franklin', 'Thomas Jefferson', 'John Adams'], correct_answer: 'Thomas Jefferson', explanation: 'Thomas Jefferson was the primary author of the Declaration of Independence in 1776. A committee of five (including Franklin and Adams) was appointed, but Jefferson wrote most of it. He later became the 3rd US President.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What civilisation built the pyramids?', type: 'multiple_choice', options: ['Romans', 'Greeks', 'Ancient Egyptians', 'Aztecs'], correct_answer: 'Ancient Egyptians', explanation: 'The Ancient Egyptians built pyramids as tombs for their pharaohs. The most famous are at Giza. The Aztecs also built pyramids, but the Egyptian ones are much more ancient (built ~4,500 years ago).', difficulty: 1, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'In what year did Columbus reach the Americas?', type: 'typed', options: null, correct_answer: '1492', explanation: 'Christopher Columbus reached the Americas in 1492. Easy to remember with the rhyme: "In 1492, Columbus sailed the ocean blue." He landed in the Bahamas on October 12, 1492.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What war was fought between the North and South of the US?', type: 'multiple_choice', options: ['Revolutionary War', 'Civil War', 'War of 1812', 'World War I'], correct_answer: 'Civil War', explanation: 'The American Civil War (1861–1865) was fought between the Union (North) and the Confederacy (South), mainly over slavery and states\' rights. The Union won, slavery was abolished, and the country was reunited.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What is the name of the document that freed enslaved people in Confederate states?', type: 'multiple_choice', options: ['Declaration of Independence', 'Constitution', 'Emancipation Proclamation', 'Bill of Rights'], correct_answer: 'Emancipation Proclamation', explanation: 'President Lincoln issued the Emancipation Proclamation on January 1, 1863. It declared enslaved people in Confederate states to be free. It shifted the Civil War\'s focus toward ending slavery.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'Who was the 16th President of the US?', type: 'multiple_choice', options: ['Ulysses Grant', 'Abraham Lincoln', 'Andrew Jackson', 'James Polk'], correct_answer: 'Abraham Lincoln', explanation: 'Abraham Lincoln was the 16th US President (1861–1865). He led the country through the Civil War, issued the Emancipation Proclamation, and was assassinated in 1865. He is on the penny and $5 bill.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What did the Boston Tea Party protest?', type: 'multiple_choice', options: ['Slavery', 'Taxation without representation', 'The King of England', 'Religious laws'], correct_answer: 'Taxation without representation', explanation: 'In 1773, American colonists dumped 342 chests of British tea into Boston Harbor. They were protesting Britain taxing them without giving them any say in Parliament — "no taxation without representation" was their rallying cry.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What is the capital of the United States?', type: 'multiple_choice', options: ['New York', 'Los Angeles', 'Washington D.C.', 'Chicago'], correct_answer: 'Washington D.C.', explanation: 'Washington D.C. (District of Columbia) has been the US capital since 1800. It\'s not part of any state — it\'s a special federal district. New York City was briefly the first capital (1789–1790).', difficulty: 1, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'Which Native American helped the Pilgrims survive?', type: 'multiple_choice', options: ['Pocahontas', 'Squanto', 'Sitting Bull', 'Geronimo'], correct_answer: 'Squanto', explanation: 'Squanto (Tisquantum) of the Patuxent tribe helped the Pilgrims survive their first harsh winter in 1621. He taught them how to plant corn, catch fish, and navigate the land. He spoke English from earlier contact with Europeans.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What river did George Washington cross on Christmas night 1776?', type: 'multiple_choice', options: ['Mississippi', 'Ohio', 'Delaware', 'Hudson'], correct_answer: 'Delaware', explanation: 'On December 25–26, 1776, Washington crossed the icy Delaware River at night with 2,400 soldiers to surprise Hessian troops at Trenton, New Jersey. This bold move revived American morale during the Revolutionary War.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'How many original colonies were there?', type: 'typed', options: null, correct_answer: '13', explanation: 'The original 13 colonies became the first 13 states of the USA. That\'s why the American flag has 13 stripes (7 red, 6 white) — one for each original colony. The 50 stars represent today\'s 50 states.', difficulty: 1, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What was the main crop grown in the Southern colonies?', type: 'multiple_choice', options: ['Wheat', 'Corn', 'Tobacco', 'Rice only'], correct_answer: 'Tobacco', explanation: 'Tobacco was the most profitable crop in the Southern colonies, especially Virginia. It was so valuable it was used as currency. The demand for tobacco labor drove the expansion of slavery in the South.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'Who was the first woman to fly solo across the Atlantic?', type: 'multiple_choice', options: ['Marie Curie', 'Amelia Earhart', 'Rosa Parks', 'Susan B. Anthony'], correct_answer: 'Amelia Earhart', explanation: 'Amelia Earhart became the first woman to fly solo across the Atlantic Ocean in May 1932. She flew from Newfoundland, Canada to Northern Ireland in about 15 hours, breaking records and inspiring generations of aviators.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 5, question_text: 'What invention by Gutenberg changed history?', type: 'multiple_choice', options: ['Steam engine', 'Printing press', 'Telephone', 'Compass'], correct_answer: 'Printing press', explanation: 'Johannes Gutenberg invented the movable-type printing press around 1440. Before this, books were hand-copied (very slow and expensive). The printing press made books affordable, spreading knowledge and fueling the Renaissance and Reformation.', difficulty: 3, source: 'curated' },

  // ── HISTORY Grade 8 ──────────────────────────────────────────
  { subject: 'history', grade_level: 8, question_text: 'What year did World War II end?', type: 'typed', options: null, correct_answer: '1945', explanation: 'WWII ended in 1945: Germany surrendered on May 8, 1945 (V-E Day), and Japan surrendered on August 15, 1945 (V-J Day), after atomic bombs were dropped on Hiroshima and Nagasaki.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What caused the Great Depression?', type: 'multiple_choice', options: ['World War I', 'Stock market crash of 1929', 'Hurricane of 1928', 'Drought in 1930'], correct_answer: 'Stock market crash of 1929', explanation: 'The Great Depression began with the Wall Street stock market crash on October 29, 1929 ("Black Tuesday"). Banks failed, businesses closed, and unemployment reached 25%. It lasted through the 1930s and was ended mainly by WWII spending.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What year did World War I begin?', type: 'typed', options: null, correct_answer: '1914', explanation: 'WWI began in 1914 after Archduke Franz Ferdinand of Austria-Hungary was assassinated on June 28, 1914. This triggered a chain of alliances that pulled most of Europe into war. It lasted until 1918.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'Who was the US President during World War II?', type: 'multiple_choice', options: ['Woodrow Wilson', 'Harry Truman', 'Franklin D. Roosevelt', 'Dwight Eisenhower'], correct_answer: 'Franklin D. Roosevelt', explanation: 'FDR (Franklin D. Roosevelt) was President for most of WWII (1933–1945). He died in April 1945, just before the war ended, and was succeeded by Harry Truman, who made the decision to use atomic bombs.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the name of the Nazi leader of Germany?', type: 'multiple_choice', options: ['Mussolini', 'Stalin', 'Hitler', 'Franco'], correct_answer: 'Hitler', explanation: 'Adolf Hitler became Chancellor of Germany in 1933 and later its dictator (Führer). His Nazi party promoted extreme nationalism and antisemitism, leading to WWII and the Holocaust. Mussolini led Italy, Stalin led the USSR.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What event triggered the US entry into WWII?', type: 'multiple_choice', options: ['D-Day', 'Attack on Pearl Harbor', 'Invasion of Poland', 'Fall of Berlin'], correct_answer: 'Attack on Pearl Harbor', explanation: 'On December 7, 1941, Japan launched a surprise attack on the US naval base at Pearl Harbor, Hawaii, killing over 2,400 Americans. The next day, the US declared war on Japan, bringing America into WWII.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the Cold War?', type: 'multiple_choice', options: ['A war fought in Antarctica', 'Tension between US and Soviet Union', 'A World War III', 'A war about oil'], correct_answer: 'Tension between US and Soviet Union', explanation: 'The Cold War (1947–1991) was a period of political and military tension between the US (capitalism/democracy) and Soviet Union (communism). "Cold" means no direct fighting between the two superpowers, though proxy wars occurred.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'In what year did the Berlin Wall fall?', type: 'typed', options: null, correct_answer: '1989', explanation: 'The Berlin Wall fell on November 9, 1989. The Wall had divided communist East Berlin from democratic West Berlin since 1961. Its fall symbolized the end of the Cold War and led to Germany\'s reunification in 1990.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the Holocaust?', type: 'multiple_choice', options: ['A battle in WWI', 'Nazi genocide of Jewish people', 'The bombing of Hiroshima', 'The Great Depression'], correct_answer: 'Nazi genocide of Jewish people', explanation: 'The Holocaust was the systematic murder of 6 million Jewish people (and millions of others) by the Nazi regime from 1941–1945. The Nazis used concentration camps and death camps. It is one of history\'s worst genocides.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'Which country did Germany first invade to start WWII?', type: 'multiple_choice', options: ['France', 'USSR', 'Poland', 'Belgium'], correct_answer: 'Poland', explanation: 'Germany invaded Poland on September 1, 1939. Britain and France had guaranteed Poland\'s independence, so they declared war on Germany two days later on September 3, 1939 — officially starting WWII.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the Marshall Plan?', type: 'multiple_choice', options: ['A military strategy', 'US aid to rebuild Europe after WWII', 'A peace treaty', 'A nuclear agreement'], correct_answer: 'US aid to rebuild Europe after WWII', explanation: 'The Marshall Plan (1948–1952), named after Secretary of State George Marshall, provided $13 billion in US aid to rebuild war-devastated Western Europe. It also helped prevent the spread of communism to economically weak nations.', difficulty: 4, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the name of the first atomic bomb dropped on Japan?', type: 'multiple_choice', options: ['Fat Man', 'Little Boy', 'Big Bang', 'Thunder'], correct_answer: 'Little Boy', explanation: '"Little Boy" was dropped on Hiroshima on August 6, 1945. "Fat Man" was dropped on Nagasaki on August 9, 1945. Together, they caused Japan\'s surrender and ended WWII. The names refer to their shapes.', difficulty: 4, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'Who was Martin Luther King Jr.?', type: 'multiple_choice', options: ['A US President', 'A Civil Rights leader', 'A war general', 'A scientist'], correct_answer: 'A Civil Rights leader', explanation: 'MLK Jr. was a Baptist minister and leader of the Civil Rights Movement. His "I Have a Dream" speech (1963) and nonviolent protests were key to passing the Civil Rights Act of 1964 and Voting Rights Act of 1965.', difficulty: 1, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What year did the US land on the Moon?', type: 'typed', options: null, correct_answer: '1969', explanation: 'Apollo 11 landed on the Moon on July 20, 1969. Neil Armstrong was the first human to walk on the Moon, followed by Buzz Aldrin. Armstrong said: "That\'s one small step for man, one giant leap for mankind."', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the name of the first artificial satellite launched into space?', type: 'multiple_choice', options: ['Apollo 11', 'Explorer 1', 'Sputnik', 'Vostok'], correct_answer: 'Sputnik', explanation: 'The Soviet Union launched Sputnik 1 on October 4, 1957 — the first artificial satellite. It shocked the US and started the Space Race. The word "sputnik" means "fellow traveler" in Russian.', difficulty: 3, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What movement fought for African American civil rights in the 1950s–60s?', type: 'multiple_choice', options: ['Suffrage Movement', 'Civil Rights Movement', 'Labor Movement', 'Prohibition'], correct_answer: 'Civil Rights Movement', explanation: 'The Civil Rights Movement (1954–1968) fought to end racial segregation and discrimination through marches, sit-ins, and legislation. Key events: Montgomery Bus Boycott, March on Washington, Selma marches, Civil Rights Act of 1964.', difficulty: 2, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'Who was the first Black President of the US?', type: 'multiple_choice', options: ['Bill Clinton', 'Barack Obama', 'Joe Biden', 'Jesse Jackson'], correct_answer: 'Barack Obama', explanation: 'Barack Obama was elected the 44th President of the United States in 2008 and re-elected in 2012, becoming the first African American president in US history. He served until 2017.', difficulty: 1, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the name of the operation to liberate Western Europe on June 6, 1944?', type: 'multiple_choice', options: ['Operation Overlord', 'Operation Torch', 'Operation Market Garden', 'D-Plan'], correct_answer: 'Operation Overlord', explanation: 'Operation Overlord was the codename for the D-Day invasion on June 6, 1944. Over 156,000 Allied troops landed on 5 Normandy beaches in France. It was the largest seaborne invasion in history and turned the tide against Nazi Germany.', difficulty: 4, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What was the League of Nations?', type: 'multiple_choice', options: ['A sports league', 'An early international peace organization', 'A trade union', 'A military alliance'], correct_answer: 'An early international peace organization', explanation: 'The League of Nations was created after WWI in 1920 to prevent future wars through diplomacy and collective security. It was US President Woodrow Wilson\'s idea, but ironically the US Senate never joined. It was replaced by the United Nations after WWII.', difficulty: 4, source: 'curated' },
  { subject: 'history', grade_level: 8, question_text: 'What does "suffrage" mean?', type: 'multiple_choice', options: ['The right to work', 'The right to vote', 'The right to education', 'The right to bear arms'], correct_answer: 'The right to vote', explanation: 'Suffrage means the right to vote in political elections. The Women\'s Suffrage Movement fought for women\'s right to vote — achieved in the US with the 19th Amendment in 1920. "Universal suffrage" means everyone gets to vote.', difficulty: 3, source: 'curated' },

  // ── ENGLISH Grade 4 ──────────────────────────────────────────
  { subject: 'english', grade_level: 4, question_text: 'What is a synonym for "happy"?', type: 'multiple_choice', options: ['Sad', 'Joyful', 'Angry', 'Tired'], correct_answer: 'Joyful', explanation: 'Synonyms are words with the same or similar meaning. "Joyful" means feeling great happiness — same idea as "happy." Other synonyms: pleased, cheerful, content, elated. "Sad" is an antonym (opposite).', difficulty: 1, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'Which of these is a noun?', type: 'multiple_choice', options: ['Run', 'Quickly', 'Beautiful', 'Apple'], correct_answer: 'Apple', explanation: 'A noun is a person, place, thing, or idea. "Apple" is a thing (fruit) — it\'s a noun. "Run" is a verb (action). "Quickly" is an adverb (how). "Beautiful" is an adjective (describes something).', difficulty: 1, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What punctuation ends a question?', type: 'multiple_choice', options: ['Period', 'Exclamation mark', 'Question mark', 'Comma'], correct_answer: 'Question mark', explanation: 'Sentences that ask something end with a question mark (?). Example: "What time is it?" Declarative sentences end with a period. Exclamatory sentences end with an exclamation mark (!).', difficulty: 1, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is the plural of "child"?', type: 'typed', options: null, correct_answer: 'children', explanation: '"Child" has an irregular plural — it doesn\'t follow the normal rule of adding -s or -es. The plural is "children." Other irregular plurals: man→men, woman→women, tooth→teeth, foot→feet, mouse→mice.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'Which word is an adjective?', type: 'multiple_choice', options: ['Jump', 'Slowly', 'Bright', 'They'], correct_answer: 'Bright', explanation: 'Adjectives describe or modify nouns. "Bright" describes things (a bright light, bright student). "Jump" is a verb, "slowly" is an adverb, "they" is a pronoun.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is the plural of "mouse"?', type: 'typed', options: null, correct_answer: 'mice', explanation: '"Mouse" has an irregular plural — not "mouses." The plural is "mice." This is an Old English pattern where the vowel changes: mouse→mice, louse→lice, goose→geese.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is an antonym of "hot"?', type: 'multiple_choice', options: ['Warm', 'Boiling', 'Cold', 'Spicy'], correct_answer: 'Cold', explanation: 'Antonyms are words with opposite meanings. "Cold" is the opposite of "hot." "Warm" is similar to hot (synonym-ish), "boiling" is even hotter, and "spicy" is a different meaning of "hot."', difficulty: 1, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'Which sentence is correct?', type: 'multiple_choice', options: ['She go to school.', 'She goes to school.', 'She going to school.', 'She gone to school.'], correct_answer: 'She goes to school.', explanation: '"She" is a third-person singular pronoun (he/she/it). These need the verb to end in -s in present tense: I go, you go, he/she/it GOES. "She go" is grammatically wrong — it needs "goes."', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What does the prefix "un-" mean?', type: 'multiple_choice', options: ['Again', 'Before', 'Not', 'Under'], correct_answer: 'Not', explanation: 'The prefix "un-" means "not" or "the opposite of." Examples: unhappy = not happy, undo = reverse doing, unfair = not fair. "Re-" means again, "pre-" means before, "sub-" means under.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'Which word is a verb?', type: 'multiple_choice', options: ['Happy', 'Quickly', 'Dance', 'Blue'], correct_answer: 'Dance', explanation: 'Verbs are action words or state-of-being words. "Dance" is an action you can do. "Happy" is an adjective, "quickly" is an adverb, "blue" is an adjective. Ask yourself: "Can I ___?" — "Can I dance?" Yes!', difficulty: 1, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is a sentence that asks something called?', type: 'multiple_choice', options: ['Exclamatory', 'Declarative', 'Interrogative', 'Imperative'], correct_answer: 'Interrogative', explanation: '"Interrogative" comes from Latin "interrogare" meaning to question. The 4 sentence types: Declarative (statement), Interrogative (question), Imperative (command), Exclamatory (strong feeling/!).', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is the past tense of "run"?', type: 'typed', options: null, correct_answer: 'ran', explanation: '"Run" is an irregular verb — it doesn\'t follow the normal rule of adding -ed. The past tense is "ran." Other irregular verbs: go→went, see→saw, come→came, give→gave, take→took.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What do you call words that sound the same but mean different things?', type: 'multiple_choice', options: ['Synonyms', 'Antonyms', 'Homophones', 'Prefixes'], correct_answer: 'Homophones', explanation: '"Homo" means same, "phone" means sound. Homophones sound alike but have different meanings/spellings: there/their/they\'re, to/too/two, here/hear, right/write. Don\'t confuse with synonyms (same meaning) or antonyms (opposite meaning).', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'Which word completes: "The dog wagged ___ tail"?', type: 'multiple_choice', options: ['it', 'his', 'their', 'our'], correct_answer: 'his', explanation: 'A pronoun must agree with the noun it refers to. "The dog" is singular and masculine (he/his). "Their" is plural. "Our" includes the speaker. "It" works for objects, but for animals we often use "his" or "her."', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is the plural of "leaf"?', type: 'typed', options: null, correct_answer: 'leaves', explanation: 'Words ending in "-f" or "-fe" usually change to "-ves" in the plural: leaf→leaves, knife→knives, wolf→wolves, half→halves, life→lives. This is a spelling rule to memorise!', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What mark goes at the end of an exclamation?', type: 'multiple_choice', options: ['Period', 'Question mark', 'Exclamation mark', 'Comma'], correct_answer: 'Exclamation mark', explanation: 'An exclamation mark (!) ends a sentence expressing strong emotion, surprise, or excitement. "Watch out!" "That\'s amazing!" A period ends regular statements, a question mark ends questions.', difficulty: 1, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is the opposite of "ancient"?', type: 'multiple_choice', options: ['Old', 'Modern', 'Historic', 'Dusty'], correct_answer: 'Modern', explanation: '"Ancient" means very old (from thousands of years ago). Its antonym (opposite) is "modern," meaning current, new, or of today. "Old" and "historic" are similar in meaning to ancient, not opposite.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What type of word is "she", "he", "they"?', type: 'multiple_choice', options: ['Noun', 'Verb', 'Pronoun', 'Adjective'], correct_answer: 'Pronoun', explanation: 'Pronouns replace nouns to avoid repetition. Instead of "Maria went to Maria\'s class," we say "She went to her class." Personal pronouns: I, you, he, she, it, we, they.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'What is the past tense of "eat"?', type: 'typed', options: null, correct_answer: 'ate', explanation: '"Eat" is an irregular verb — past tense is "ate," not "eated." The past participle is "eaten" (I have eaten). Irregular verbs must be memorised: eat→ate, drink→drank, sing→sang.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 4, question_text: 'A word that describes a verb is called a(n)...', type: 'multiple_choice', options: ['Adjective', 'Adverb', 'Pronoun', 'Conjunction'], correct_answer: 'Adverb', explanation: 'Adverbs describe verbs (and adjectives/other adverbs). They often answer "how?", "when?", "where?", or "how much?" Examples: run QUICKLY, speak LOUDLY, arrive SOON. Many adverbs end in -ly.', difficulty: 3, source: 'curated' },

  // ── ENGLISH Grade 7 ──────────────────────────────────────────
  { subject: 'english', grade_level: 7, question_text: '"The wind whispered through the trees" is an example of?', type: 'multiple_choice', options: ['Simile', 'Metaphor', 'Personification', 'Alliteration'], correct_answer: 'Personification', explanation: 'Personification gives human qualities to non-human things. "Whispered" is a human action — wind can\'t actually whisper. This makes the description more vivid and relatable. (Simile uses "like/as," metaphor says one thing IS another.)', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is the main clause in: "Although it rained, we played outside"?', type: 'multiple_choice', options: ['Although it rained', 'We played outside', 'It rained', 'Although we played'], correct_answer: 'We played outside', explanation: 'The main clause can stand alone as a complete sentence. "We played outside" makes sense alone. "Although it rained" is a subordinate clause — it depends on the main clause. "Although" signals a dependent clause.', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is an antonym for "ancient"?', type: 'multiple_choice', options: ['Old', 'Modern', 'Historic', 'Vintage'], correct_answer: 'Modern', explanation: '"Ancient" = very old. Its antonym (opposite) is "modern" = current/new. "Old," "historic," and "vintage" are all similar in meaning to ancient, so they\'re not opposites.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: '"As brave as a lion" is a?', type: 'multiple_choice', options: ['Metaphor', 'Simile', 'Hyperbole', 'Alliteration'], correct_answer: 'Simile', explanation: 'A simile compares two things using "like" or "as." "As brave AS a lion" uses "as" — it\'s a simile. A metaphor would say "He IS a lion" (no like/as). Easy trick: Simile = has a "s" like "as" and "is."', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is the theme of a story?', type: 'multiple_choice', options: ['The setting', 'The central message', 'The main character', 'The plot twist'], correct_answer: 'The central message', explanation: 'Theme is the underlying message or lesson of a story — the big idea the author wants you to take away. Examples: "love conquers all," "power corrupts," "be yourself." It\'s different from the plot (what happens) or setting (where/when).', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: '"I\'ve told you a million times" is an example of?', type: 'multiple_choice', options: ['Simile', 'Personification', 'Hyperbole', 'Alliteration'], correct_answer: 'Hyperbole', explanation: 'Hyperbole is deliberate exaggeration for emphasis or humor. You haven\'t literally said it a million times — it\'s an overstatement. Other examples: "I\'m so hungry I could eat a horse," "I\'ve been waiting forever."', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What does "protagonist" mean?', type: 'multiple_choice', options: ['The villain', 'The main character', 'The narrator', 'The setting'], correct_answer: 'The main character', explanation: 'Protagonist comes from Greek: "protos" (first) + "agonist" (actor). The protagonist is the main character the story follows. The antagonist is their opponent/villain. Harry Potter is the protagonist; Voldemort is the antagonist.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is foreshadowing?', type: 'multiple_choice', options: ['A flashback to the past', 'A hint of what will happen', 'A description of the setting', 'Dialogue between characters'], correct_answer: 'A hint of what will happen', explanation: 'Foreshadowing is when an author gives clues about what will happen later. Example: In Romeo and Juliet, Romeo says "my life were better ended by their hate" — foreshadowing his death. It builds suspense and prepares the reader.', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'Which is an example of alliteration?', type: 'multiple_choice', options: ['The sun set slowly', 'Peter Piper picked peppers', 'She is like a rose', 'Time flies'], correct_answer: 'Peter Piper picked peppers', explanation: 'Alliteration is the repetition of the same consonant sound at the start of nearby words. "Peter Piper Picked Peppers" — all start with the "P" sound. It creates rhythm and is used in poetry and tongue twisters.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is a synonym for "melancholy"?', type: 'multiple_choice', options: ['Joyful', 'Sad', 'Angry', 'Confused'], correct_answer: 'Sad', explanation: '"Melancholy" means a deep, pensive sadness. It\'s a formal/literary word. Synonyms: sad, sorrowful, gloomy, mournful, dejected. Antonyms: joyful, elated, cheerful. Example: "He felt a melancholy sadness as autumn arrived."', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is the difference between "their", "there", and "they\'re"?', type: 'multiple_choice', options: ['No difference', 'Possessive, place, contraction', 'All are contractions', 'All are possessives'], correct_answer: 'Possessive, place, contraction', explanation: '"Their" = possessive (belonging to them — "their house"). "There" = place or existence ("over there," "there is"). "They\'re" = contraction of "they are" ("they\'re happy"). These are homophones — they sound the same but mean different things.', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What does the suffix "-tion" typically indicate?', type: 'multiple_choice', options: ['An adjective', 'A noun', 'A verb', 'An adverb'], correct_answer: 'A noun', explanation: 'The suffix "-tion" (and "-sion," "-ation") turns verbs into nouns. Examples: create→creation, act→action, educate→education, decide→decision. These are all nouns — they\'re things or ideas, not actions.', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is the antagonist in a story?', type: 'multiple_choice', options: ['The hero', 'The narrator', 'The opponent of the protagonist', 'The setting'], correct_answer: 'The opponent of the protagonist', explanation: 'The antagonist opposes or conflicts with the protagonist. They\'re often the villain but not always — it could be nature, society, or the protagonist\'s own inner conflict. "Antagonize" means to oppose or make an enemy.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: '"Life is a rollercoaster" is a?', type: 'multiple_choice', options: ['Simile', 'Metaphor', 'Hyperbole', 'Personification'], correct_answer: 'Metaphor', explanation: 'A metaphor says one thing IS another (without using like/as). "Life IS a rollercoaster" — life is directly compared to a rollercoaster, implying ups and downs. A simile would say "Life is LIKE a rollercoaster."', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is the correct word: "I (accept/except) your apology"?', type: 'multiple_choice', options: ['except', 'accept', 'Both work', 'Neither works'], correct_answer: 'accept', explanation: '"Accept" is a verb meaning to receive or agree to. "Except" is a preposition/conjunction meaning excluding or but for. "I accept your apology" = I receive/acknowledge it. "Everyone except Tom" = everyone but Tom.', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What narrative point of view uses "I" and "we"?', type: 'multiple_choice', options: ['Second person', 'Third person', 'First person', 'Omniscient'], correct_answer: 'First person', explanation: 'First person = I, me, we, us (narrator is IN the story). Second person = you (rare, reader is addressed directly). Third person = he, she, they, it (narrator is outside the story). Example: "I walked into the room" = first person.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is the climax of a story?', type: 'multiple_choice', options: ['The beginning', 'The turning point of highest tension', 'The resolution', 'The setting introduction'], correct_answer: 'The turning point of highest tension', explanation: 'Story structure: Exposition (intro) → Rising Action → CLIMAX (highest tension/turning point) → Falling Action → Resolution. The climax is the most exciting moment — like the final battle in Harry Potter or the key decision a character makes.', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'Which sentence uses correct punctuation?', type: 'multiple_choice', options: ["Its a great day.", "It's a great day.", "Its' a great day.", "Its a great day!"], correct_answer: "It's a great day.", explanation: '"It\'s" is a contraction of "it is" — the apostrophe replaces the missing letter "i." "Its" (no apostrophe) is possessive, meaning belonging to it: "The dog wagged its tail." "Its\'" doesn\'t exist.', difficulty: 2, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What is an inference?', type: 'multiple_choice', options: ['A direct quote', 'A conclusion drawn from evidence', 'A summary', 'A character description'], correct_answer: 'A conclusion drawn from evidence', explanation: 'An inference is a logical conclusion you reach from clues, not stated directly. Example: "She wore a raincoat and carried an umbrella" — you infer it\'s raining or will rain, even though it\'s not said. Inferences use evidence + prior knowledge.', difficulty: 3, source: 'curated' },
  { subject: 'english', grade_level: 7, question_text: 'What does "irony" mean?', type: 'multiple_choice', options: ['Repeating a sound', 'The opposite of what is expected', 'A very sad event', 'A comparison using "like"'], correct_answer: 'The opposite of what is expected', explanation: 'Irony is when the opposite of what is expected or intended happens/is said. Types: Verbal irony = saying the opposite of what you mean ("Great weather!" during a storm). Situational irony = unexpected outcome. Dramatic irony = audience knows something characters don\'t.', difficulty: 4, source: 'curated' },
]

export function getQuestionsForBattle(subject: Subject, gradeLevel: number, count = 10): Omit<Question, 'id'>[] {
  let pool = SEED_QUESTIONS.filter(q => q.subject === subject && q.grade_level === gradeLevel)

  // Fall back to nearest grade if not enough questions
  if (pool.length < count) {
    const availableGrades = [...new Set(SEED_QUESTIONS.filter(q => q.subject === subject).map(q => q.grade_level))]
    const nearest = availableGrades.reduce((prev, curr) =>
      Math.abs(curr - gradeLevel) < Math.abs(prev - gradeLevel) ? curr : prev
    )
    pool = SEED_QUESTIONS.filter(q => q.subject === subject && q.grade_level === nearest)
  }

  // Fisher-Yates shuffle for true randomness
  const arr = [...pool]
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]]
  }
  return arr.slice(0, count)
}
